8	export function quote(input: { items: Array<{ type: string }> }): number {
9	  const itemsTotal = input.items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
10	  const withSurcharge = itemsTotal === 0 ? 0 : itemsTotal * 1.1;
11	  const total = withSurcharge + PROCESSING_FEE;
12	  return Math.ceil(Math.round(total * 1e6) / 1e6);
13	}
